  t.create_user_name, t.class_id, c.name as class_name
from t_task_exam t
left join t_class c on c.id = t.class_id

    and t.deleted='f'

    and t.grade_level = #{gradeLevel}


    and t.class_id = #{classId}




        and t.class_id in

          #{id}



        and 1 = 0

select
from t_task_exam where deleted='f' and class_id is null
and grade_level = #{gradeLevel,jdbcType=INTEGER}

select

from t_task_exam
where deleted='f'
  and (
    (class_id is null

